import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"IntroduĂ§ĂŁo: Gateway AI Local | Antigravity Manager","description":"Entenda o posicionamento principal do Antigravity Manager. Ele fornece uma aplicaĂ§ĂŁo de desktop e um gateway HTTP local, suporta mĂşltiplos endpoints de protocolos e agendamento de pool de contas, ajudando vocĂŞ a comeĂ§ar rapidamente com proxy reverso local e evitar erros comuns de configuraĂ§ĂŁo.","frontmatter":{"title":"IntroduĂ§ĂŁo: Gateway AI Local | Antigravity Manager","sidebarTitle":"O que Ă© um Gateway AI Local","subtitle":"O que Ă© o Antigravity Tools: Transformar 'Conta + Protocolo' em um Gateway AI Local","description":"Entenda o posicionamento principal do Antigravity Manager. Ele fornece uma aplicaĂ§ĂŁo de desktop e um gateway HTTP local, suporta mĂşltiplos endpoints de protocolos e agendamento de pool de contas, ajudando vocĂŞ a comeĂ§ar rapidamente com proxy reverso local e evitar erros comuns de configuraĂ§ĂŁo.","tags":["Iniciante","Conceito","Gateway Local","API Proxy"],"prerequisite":[],"order":1},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/start/getting-started/index.md"}`),i={name:"pt/lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function s(n,e,l,c,d,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="o-que-e-o-antigravity-tools-transformar-conta-protocolo-em-um-gateway-ai-local" tabindex="-1">O que Ă© o Antigravity Tools: Transformar &quot;Conta + Protocolo&quot; em um Gateway AI Local <a class="header-anchor" href="#o-que-e-o-antigravity-tools-transformar-conta-protocolo-em-um-gateway-ai-local" aria-label="Permalink to &quot;O que Ă© o Antigravity Tools: Transformar &quot;Conta + Protocolo&quot; em um Gateway AI Local&quot;">â€‹</a></h1><p>Para muitos clientes/SDKs AI, a barreira de entrada nĂŁo estĂˇ em &quot;saber chamar API&quot;, mas em &quot;com qual protocolo vocĂŞ realmente precisa se integrar, como gerenciar mĂşltiplas contas, como fazer com que falhas se recuperem automaticamente&quot;. O Antigravity Tools tenta consolidar essas trĂŞs coisas em um gateway local.</p><h2 id="o-que-e-o-antigravity-tools" tabindex="-1">O que Ă© o Antigravity Tools? <a class="header-anchor" href="#o-que-e-o-antigravity-tools" aria-label="Permalink to &quot;O que Ă© o Antigravity Tools?&quot;">â€‹</a></h2><p><strong>Antigravity Tools</strong> Ă© uma aplicaĂ§ĂŁo de desktop: vocĂŞ gerencia contas e configuraĂ§Ăµes na GUI, ela inicia um serviĂ§o de proxy reverso HTTP na sua mĂˇquina, encaminha uniformemente solicitaĂ§Ăµes de diferentes fabricantes/protocolos para o upstream, e converte as respostas de volta ao formato familiar do cliente.</p><h2 id="o-que-voce-podera-fazer-apos-completar" tabindex="-1">O que vocĂŞ poderĂˇ fazer apĂłs completar <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-completar" aria-label="Permalink to &quot;O que vocĂŞ poderĂˇ fazer apĂłs completar&quot;">â€‹</a></h2><ul><li>Explicar claramente qual problema o Antigravity Tools resolve (e o que ele nĂŁo resolve)</li><li>Reconhecer seus componentes principais: GUI, pool de contas, gateway de proxy reverso HTTP, adaptaĂ§ĂŁo de protocolo</li><li>Entender os limites de seguranĂ§a padrĂŁo (127.0.0.1, porta, modo de autenticaĂ§ĂŁo) e quando precisam ser alterados</li><li>Saber para qual capĂ­tulo ir a seguir: instalaĂ§ĂŁo, adicionar conta, iniciar proxy, conectar cliente</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">â€‹</a></h2><p>VocĂŞ pode ter encontrado esses problemas:</p><ul><li>O mesmo cliente precisa suportar trĂŞs protocolos (OpenAI/Anthropic/Gemini), as configuraĂ§Ăµes ficam bagunĂ§adas</li><li>Tem mĂşltiplas contas, mas alternĂ˘ncia, rotaĂ§ĂŁo e limitaĂ§ĂŁo de taxa com retry sĂŁo manuais</li><li>Quando as solicitaĂ§Ăµes falham, vocĂŞ sĂł pode adivinhar nos logs se Ă© &quot;conta invĂˇlida&quot; ou &quot;limite de upstream/capacidade esgotada&quot;</li></ul><p>O objetivo do Antigravity Tools Ă© fazer esse &quot;trabalho de borda&quot; entrar em um gateway local, permitindo que seu cliente/SDK se preocupe apenas com uma coisa: enviar solicitaĂ§Ăµes para o local.</p><h2 id="ideia-principal" tabindex="-1">Ideia Principal <a class="header-anchor" href="#ideia-principal" aria-label="Permalink to &quot;Ideia Principal&quot;">â€‹</a></h2><p>VocĂŞ pode entendĂŞ-lo como um &quot;gateway de agendamento AI&quot; local, composto por trĂŞs camadas:</p><ol><li>GUI (AplicaĂ§ĂŁo de Desktop)</li></ol><ul><li>ResponsĂˇvel por permitir que vocĂŞ gerencie contas, configuraĂ§Ăµes, monitoramento e estatĂ­sticas.</li><li>PĂˇgina principal: Dashboard, Accounts, API Proxy, Monitor, Token Stats, Settings.</li></ul><ol start="2"><li>ServiĂ§o de Proxy Reverso HTTP (Axum Server)</li></ol><ul><li>ResponsĂˇvel por expor mĂşltiplos endpoints de protocolo externamente e encaminhar solicitaĂ§Ăµes para o handler correspondente.</li><li>O serviĂ§o de proxy reverso monta camadas de autenticaĂ§ĂŁo, middleware de monitoramento, CORS, Trace, etc.</li></ul><ol start="3"><li>Pool de Contas e Agendamento (TokenManager, etc.)</li></ol><ul><li>ResponsĂˇvel por selecionar contas disponĂ­veis do pool de contas local, atualizar tokens quando necessĂˇrio, fazer rotaĂ§ĂŁo e auto-recuperaĂ§ĂŁo.</li></ul><div class="info custom-block"><p class="custom-block-title">O que significa &quot;gateway local&quot;?</p><p>Aqui &quot;local&quot; Ă© literal: o serviĂ§o roda na sua prĂłpria mĂˇquina, seus clientes (Claude Code, OpenAI SDK, vĂˇrios clientes de terceiros) apontam o Base URL para <code>http://127.0.0.1:&lt;port&gt;</code>, as solicitaĂ§Ăµes chegam primeiro na sua mĂˇquina, depois sĂŁo encaminhadas pelo Antigravity Tools para o upstream.</p></div><h2 id="quais-endpoints-ele-expoe-externamente" tabindex="-1">Quais endpoints ele expĂµe externamente <a class="header-anchor" href="#quais-endpoints-ele-expoe-externamente" aria-label="Permalink to &quot;Quais endpoints ele expĂµe externamente&quot;">â€‹</a></h2><p>O serviĂ§o de proxy reverso registra mĂşltiplos conjuntos de endpoints de protocolo em um Router, vocĂŞ pode primeiro lembrar estas &quot;entradas&quot;:</p><ul><li>CompatĂ­vel com OpenAI: <code>/v1/chat/completions</code>, <code>/v1/completions</code>, <code>/v1/responses</code>, <code>/v1/models</code></li><li>CompatĂ­vel com Anthropic: <code>/v1/messages</code>, <code>/v1/messages/count_tokens</code></li><li>Nativo Gemini: <code>/v1beta/models</code>, <code>/v1beta/models/:model</code>, <code>/v1beta/models/:model/countTokens</code></li><li>VerificaĂ§ĂŁo de saĂşde: <code>GET /healthz</code></li></ul><p>Se seu cliente pode integrar qualquer um desses protocolos, teoricamente pode, atravĂ©s de &quot;mudar o Base URL&quot;, direcionar solicitaĂ§Ăµes para este gateway local.</p><h2 id="limites-de-seguranca-padrao-nao-pule" tabindex="-1">Limites de seguranĂ§a padrĂŁo (nĂŁo pule) <a class="header-anchor" href="#limites-de-seguranca-padrao-nao-pule" aria-label="Permalink to &quot;Limites de seguranĂ§a padrĂŁo (nĂŁo pule)&quot;">â€‹</a></h2><p>O maior problema com esse tipo de &quot;proxy reverso local&quot; geralmente nĂŁo Ă© falta de funcionalidade, mas vocĂŞ acidentalmente o expor para fora.</p><p>Primeiro, lembre alguns valores padrĂŁo (todos vindos da configuraĂ§ĂŁo padrĂŁo):</p><ul><li>Porta padrĂŁo: <code>8045</code></li><li>Apenas acesso local por padrĂŁo: <code>allow_lan_access=false</code>, endereĂ§o de escuta <code>127.0.0.1</code></li><li>Modo de autenticaĂ§ĂŁo padrĂŁo: <code>auth_mode=off</code> (nĂŁo exige que o cliente traga key)</li><li>Por padrĂŁo, gerarĂˇ um <code>api_key</code> no formato <code>sk-...</code> (para vocĂŞ habilitar quando precisar de autenticaĂ§ĂŁo)</li></ul><div class="warning custom-block"><p class="custom-block-title">Quando vocĂŞ deve habilitar autenticaĂ§ĂŁo?</p><p>Sempre que vocĂŞ habilitar acesso LAN (<code>allow_lan_access=true</code>, endereĂ§o de escuta torna-se <code>0.0.0.0</code>), vocĂŞ deve habilitar autenticaĂ§ĂŁo simultaneamente e tratar a API Key como uma senha.</p></div><h2 id="quando-usar-o-antigravity-tools" tabindex="-1">Quando usar o Antigravity Tools <a class="header-anchor" href="#quando-usar-o-antigravity-tools" aria-label="Permalink to &quot;Quando usar o Antigravity Tools&quot;">â€‹</a></h2><p>Ele Ă© mais adequado para estes cenĂˇrios:</p><ul><li>VocĂŞ tem mĂşltiplos clientes/SDKs AI, quer passar por um Ăşnico Base URL unificado</li><li>VocĂŞ precisa consolidar diferentes protocolos (OpenAI/Anthropic/Gemini) no mesmo &quot;ponto de saĂ­da local&quot;</li><li>VocĂŞ tem mĂşltiplas contas, quer que o sistema seja responsĂˇvel pela rotaĂ§ĂŁo e tratamento de estabilidade</li></ul><p>Se vocĂŞ sĂł quer &quot;escrever duas linhas de cĂłdigo para chamar diretamente a API oficial&quot;, e suas contas/protocolos sĂŁo fixos, pode ser um pouco pesado.</p><h2 id="siga-me-primeiro-estabeleca-a-ordem-correta-de-uso" tabindex="-1">Siga-me: primeiro estabeleĂ§a a ordem correta de uso <a class="header-anchor" href="#siga-me-primeiro-estabeleca-a-ordem-correta-de-uso" aria-label="Permalink to &quot;Siga-me: primeiro estabeleĂ§a a ordem correta de uso&quot;">â€‹</a></h2><p>Esta aula nĂŁo ensina configuraĂ§Ăµes detalhadas, apenas alinha a ordem principal para evitar que vocĂŞ pule e fique preso:</p><h3 id="passo-1-primeiro-instale-e-inicie" tabindex="-1">Passo 1: Primeiro instale e inicie <a class="header-anchor" href="#passo-1-primeiro-instale-e-inicie" aria-label="Permalink to &quot;Passo 1: Primeiro instale e inicie&quot;">â€‹</a></h3><p><strong>Por que</strong> A aplicaĂ§ĂŁo de desktop Ă© responsĂˇvel pelo gerenciamento de contas e iniciar o serviĂ§o de proxy reverso. Sem ela, OAuth/proxy subsequente nĂŁo tĂŞm sentido.</p><p>VĂˇ para o prĂłximo capĂ­tulo e complete a instalaĂ§ĂŁo seguindo o README.</p><p><strong>VocĂŞ deve ver</strong>: VocĂŞ pode abrir o Antigravity Tools e ver a pĂˇgina Dashboard.</p><h3 id="passo-2-adicione-pelo-menos-uma-conta" tabindex="-1">Passo 2: Adicione pelo menos uma conta <a class="header-anchor" href="#passo-2-adicione-pelo-menos-uma-conta" aria-label="Permalink to &quot;Passo 2: Adicione pelo menos uma conta&quot;">â€‹</a></h3><p><strong>Por que</strong> O serviĂ§o de proxy reverso precisa obter uma identidade disponĂ­vel do pool de contas para enviar solicitaĂ§Ăµes ao upstream. Sem contas, o gateway nĂŁo pode &quot;chamar em seu nome&quot;.</p><p>VĂˇ para o capĂ­tulo &quot;Adicionar Conta&quot; e adicione a conta seguindo o fluxo OAuth ou Refresh Token.</p><p><strong>VocĂŞ deve ver</strong>: Sua conta aparece na pĂˇgina Accounts, e vocĂŞ pode ver informaĂ§Ăµes de cota/estado.</p><h3 id="passo-3-inicie-o-api-proxy-e-faca-a-verificacao-minima-com-healthz" tabindex="-1">Passo 3: Inicie o API Proxy e faĂ§a a verificaĂ§ĂŁo mĂ­nima com /healthz <a class="header-anchor" href="#passo-3-inicie-o-api-proxy-e-faca-a-verificacao-minima-com-healthz" aria-label="Permalink to &quot;Passo 3: Inicie o API Proxy e faĂ§a a verificaĂ§ĂŁo mĂ­nima com /healthz&quot;">â€‹</a></h3><p><strong>Por que</strong> Primeiro use <code>GET /healthz</code> para verificar &quot;o serviĂ§o local estĂˇ rodando&quot;, depois conecte o cliente, a soluĂ§ĂŁo de problemas serĂˇ muito mais simples.</p><p>VĂˇ para o capĂ­tulo &quot;Iniciar Proxy Reverso Local e Conectar o Primeiro Cliente&quot; para completar o ciclo.</p><p><strong>VocĂŞ deve ver</strong>: Seu cliente/SDK pode obter com sucesso uma resposta atravĂ©s do Base URL local.</p><h2 id="aviso-sobre-armadilhas" tabindex="-1">Aviso sobre armadilhas <a class="header-anchor" href="#aviso-sobre-armadilhas" aria-label="Permalink to &quot;Aviso sobre armadilhas&quot;">â€‹</a></h2><table tabindex="0"><thead><tr><th>CenĂˇrio</th><th>O que vocĂŞ pode fazer (âťŚ)</th><th>PrĂˇtica recomendada (âś“)</th></tr></thead><tbody><tr><td>Quer que celular/outro PC acesse</td><td>Abra diretamente <code>allow_lan_access=true</code> mas nĂŁo configure autenticaĂ§ĂŁo</td><td>Habilite autenticaĂ§ĂŁo simultaneamente, e primeiro valide <code>GET /healthz</code> na LAN</td></tr><tr><td>Cliente reporta 404</td><td>Mude host/port apenas, nĂŁo importa como o cliente concatena <code>/v1</code></td><td>Primeiro confirme a estratĂ©gia de concatenaĂ§ĂŁo base_url do cliente, depois decida se precisa prefixar <code>/v1</code></td></tr><tr><td>ComeĂ§a logo resolvendo Claude Code</td><td>Conecte diretamente o cliente complexo, quando falhar nĂŁo sabe onde verificar</td><td>Primeiro execute o ciclo mĂ­nimo: inicie Proxy -&gt; <code>GET /healthz</code> -&gt; depois conecte o cliente</td></tr></tbody></table><h2 id="resumo-da-licao" tabindex="-1">Resumo da liĂ§ĂŁo <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da liĂ§ĂŁo&quot;">â€‹</a></h2><ul><li>O posicionamento do Antigravity Tools Ă© &quot;aplicaĂ§ĂŁo de desktop + gateway de proxy reverso HTTP local&quot;: GUI gerencia, Axum fornece mĂşltiplos endpoints de protocolo</li><li>VocĂŞ precisa tratĂˇ-lo como uma infraestrutura local: primeiro instale, adicione conta, inicie Proxy, conecte cliente</li><li>Por padrĂŁo apenas escuta <code>127.0.0.1:8045</code>, se expor para LAN, deve habilitar autenticaĂ§ĂŁo obrigatoriamente</li></ul><h2 id="proximo-aviso-de-licao" tabindex="-1">PrĂłximo aviso de liĂ§ĂŁo <a class="header-anchor" href="#proximo-aviso-de-licao" aria-label="Permalink to &quot;PrĂłximo aviso de liĂ§ĂŁo&quot;">â€‹</a></h2><blockquote><p>Na prĂłxima liĂ§ĂŁo completamos a instalaĂ§ĂŁo: <strong><a href="./../installation/">InstalaĂ§ĂŁo e AtualizaĂ§ĂŁo: Melhor caminho de instalaĂ§ĂŁo para desktop</a></strong>.</p><p>VocĂŞ aprenderĂˇ:</p><ul><li>VĂˇrias maneiras de instalaĂ§ĂŁo listadas no README (e prioridade)</li><li>Entrada de atualizaĂ§ĂŁo e como lidar com bloqueios comuns do sistema</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">ApĂŞndice: ReferĂŞncia de cĂłdigo-fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;ApĂŞndice: ReferĂŞncia de cĂłdigo-fonte&quot;">â€‹</a></h2><details><summary><strong>Clique para expandir localizaĂ§ĂŁo do cĂłdigo-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Posicionamento do produto (hub de transbordo local AI / lacuna de protocolo)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L35-L77" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>35-77</td></tr><tr><td>VisĂŁo geral dos endpoints do Router (OpenAI/Claude/Gemini/healthz)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L120-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>120-194</td></tr><tr><td>LĂłgica de porta padrĂŁo / acesso apenas local padrĂŁo / key padrĂŁo e bind address</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L291" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-291</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Estrutura de roteamento da pĂˇgina GUI (Dashboard/Accounts/API Proxy/Monitor/Token Stats/Settings)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/App.tsx#L19-L48" target="_blank" rel="noreferrer"><code>src/App.tsx</code></a></td><td>19-48</td></tr></tbody></table><p><strong>Valores padrĂŁo principais</strong>:</p><ul><li><code>ProxyConfig.port = 8045</code>: porta padrĂŁo do serviĂ§o de proxy reverso</li><li><code>ProxyConfig.allow_lan_access = false</code>: acesso apenas local por padrĂŁo</li><li><code>ProxyAuthMode::default() = off</code>: nĂŁo requer autenticaĂ§ĂŁo por padrĂŁo</li></ul></details>',55)])])}const h=a(i,[["render",s]]);export{m as __pageData,h as default};
